import{_ as a,a as t,b as o,m as i}from"./chunks/framework.DhA78p7M.js";const p=JSON.parse(`{"title":"How It's Made","description":"A quick meta blog on how I developed this site.","frontmatter":{"title":"How It's Made","description":"A quick meta blog on how I developed this site.","longDescription":"Everyone who can, should make a personal website. So here's how I made mine.","date":"1026-2-4"},"headers":[],"relativePath":"blogs/made/index.md","filePath":"blogs/made/index.md"}`),s={name:"blogs/made/index.md"};function r(d,e,n,h,l,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="why" tabindex="-1">Why? <a class="header-anchor" href="#why" aria-label="Permalink to “Why?”">​</a></h2><p>I&#39;ve had a personal website since 10th grade. I always wanted to have a personal space to showcase what I work on, however I personally hate website development, so my sites have always been scuffed and buggy. But then, my friend <a href="https://www.outercloud.dev/" target="_blank" rel="noreferrer">Liam Hanrahan</a> built his own website, and it looked really good. So naturally, I had to improve mine.</p><p>I think everyone should have a personal website that is entirely under their control. Its a way to break free from the algorithm and show yourself freely. I&#39;d love to hear about your website when you make one!</p><div style="height:20px;"></div><h2 id="what-did-i-use" tabindex="-1">What Did I Use? <a class="header-anchor" href="#what-did-i-use" aria-label="Permalink to “What Did I Use?”">​</a></h2><p>This website is directly forked from Liam Hanrahan&#39;s website, with a few improvements of my own. I primarily do hardware and low-level software. Web dev is far from my favorite task, so naturally, I asked his permission and based my website off of his.</p><div style="height:20px;"></div><div style="height:60px;"></div>',8)])])}const f=a(s,[["render",r]]);export{p as __pageData,f as default};
